return items.map(item => {
  const cidade = item.json.name;
  const temperatura = item.json.main?.temp;

  // arredonda (pode usar Math.round, floor ou ceil dependendo da preferência)
  const tempArredondada = Math.round(temperatura);

  // monta string final
  const mensagem = `${cidade}: ${tempArredondada}°C`;

  return {
    json: {
      cidade,
      temperatura: tempArredondada,
      mensagem
    }
  };
});
